import './App.css';
import Cards from './components/Cards.jsx';
import Nav from './components/Nav';

function App() {

   function closeHandler(){
      window.alert("Emulamos que se cierra la card")
   }

   return (
      <div className='App'>
         <Nav />
         <Cards characters={characters} onClose={closeHandler}/>
      
      </div>
   );
}

export default App;
